import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Settings, Send, Square, Trash2, ChevronDown } from 'lucide-react';
import { Message, DEFAULT_MODELS } from './types';
import { useConfig } from './useConfig';
import { streamChat } from './api';
import { SettingsModal } from './SettingsModal';
import { MessageBubble } from './MessageBubble';
import './App.css';

function generateId() {
  return Math.random().toString(36).slice(2) + Date.now().toString(36);
}

export default function App() {
  const { config, setConfig } = useConfig();
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [streaming, setStreaming] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showModelMenu, setShowModelMenu] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const abortRef = useRef<AbortController | null>(null);
  const bottomRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const adjustTextarea = () => {
    const el = textareaRef.current;
    if (!el) return;
    el.style.height = 'auto';
    el.style.height = Math.min(el.scrollHeight, 240) + 'px';
  };

  const handleStop = () => {
    abortRef.current?.abort();
    setStreaming(false);
  };

  const sendMessage = useCallback(async () => {
    const text = input.trim();
    if (!text || streaming) return;

    setError(null);
    const userMsg: Message = { id: generateId(), role: 'user', content: text, timestamp: Date.now() };
    const assistantId = generateId();
    const assistantMsg: Message = { id: assistantId, role: 'assistant', content: '', timestamp: Date.now() };

    setMessages((prev) => [...prev, userMsg, assistantMsg]);
    setInput('');
    setStreaming(true);

    const controller = new AbortController();
    abortRef.current = controller;

    try {
      const history = [...messages, userMsg];
      for await (const chunk of streamChat(history, config, controller.signal)) {
        setMessages((prev) =>
          prev.map((m) => (m.id === assistantId ? { ...m, content: m.content + chunk } : m))
        );
      }
    } catch (err: any) {
      if (err.name !== 'AbortError') {
        const msg = err.message || 'Unknown error';
        setError(msg);
        setMessages((prev) => prev.filter((m) => m.id !== assistantId));
      }
    } finally {
      setStreaming(false);
    }
  }, [input, messages, config, streaming]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const clearChat = () => {
    setMessages([]);
    setError(null);
  };

  const modelLabel = DEFAULT_MODELS.find((m) => m.id === config.model)?.label ?? config.model;

  return (
    <div className="app">
      <header className="header">
        <div className="header-left">
          <span className="app-title">MyBuddy</span>
          <div className="model-picker">
            <button
              className="model-btn"
              onClick={() => setShowModelMenu((v) => !v)}
            >
              {modelLabel}
              <ChevronDown size={14} />
            </button>
            {showModelMenu && (
              <div className="model-menu">
                {DEFAULT_MODELS.map((m) => (
                  <button
                    key={m.id}
                    className={`model-option ${config.model === m.id ? 'active' : ''}`}
                    onClick={() => {
                      setConfig({ ...config, model: m.id });
                      setShowModelMenu(false);
                    }}
                  >
                    {m.label}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
        <div className="header-right">
          {messages.length > 0 && (
            <button className="icon-btn" title="Clear chat" onClick={clearChat}>
              <Trash2 size={18} />
            </button>
          )}
          <button className="icon-btn" title="Settings" onClick={() => setShowSettings(true)}>
            <Settings size={18} />
          </button>
        </div>
      </header>

      <main className="messages">
        {messages.length === 0 && (
          <div className="empty-state">
            <div className="empty-logo">M</div>
            <h2>How can I help you?</h2>
            <p>Connected to <strong>{config.baseUrl}</strong></p>
            <p className="empty-model">Model: <strong>{modelLabel}</strong></p>
          </div>
        )}
        {messages.map((msg) => (
          <MessageBubble key={msg.id} message={msg} />
        ))}
        {error && (
          <div className="error-banner">
            <strong>Error:</strong> {error}
          </div>
        )}
        <div ref={bottomRef} />
      </main>

      <div className="input-area">
        <div className="input-box">
          <textarea
            ref={textareaRef}
            className="input-textarea"
            placeholder="Message MyBuddy… (Enter to send, Shift+Enter for newline)"
            value={input}
            onChange={(e) => { setInput(e.target.value); adjustTextarea(); }}
            onKeyDown={handleKeyDown}
            rows={1}
            disabled={streaming}
          />
          <button
            className={`send-btn ${streaming ? 'stop' : ''}`}
            onClick={streaming ? handleStop : sendMessage}
            disabled={!streaming && !input.trim()}
            title={streaming ? 'Stop' : 'Send'}
          >
            {streaming ? <Square size={18} fill="currentColor" /> : <Send size={18} />}
          </button>
        </div>
        <p className="input-hint">Model: {config.model}</p>
      </div>

      {showSettings && (
        <SettingsModal
          config={config}
          onSave={setConfig}
          onClose={() => setShowSettings(false)}
        />
      )}

      {showModelMenu && (
        <div className="backdrop" onClick={() => setShowModelMenu(false)} />
      )}
    </div>
  );
}
